THE RISK:
{
 "id": "colo-denominator-mispricing-enterprise-geography",
 "title": "Colo-MW geo weights misprice the enterprise third of the cube: NL inflated, Swiss and German enterprise demand invisible by construction",
 "narrative": "Every geography share was apportioned on Statista's colocation-and-scale-colocation MW. But the segment axis says 29% of the market is enterprise on-premise — capacity that the colo denominator does not count at all. The error is not random: Switzerland's installed base including self-operated capacity is ~3x its colo figure, and Germany's installed IT load (BMWK >2,700 MW) far exceeds its 1,737 MW colo figure, while the Netherlands' weight reflects the Amsterdam colo hub, not Dutch enterprise demand. So the funnel multiplies an enterprise segment share by geo weights that systematically inflate NL×enterprise and starve CH×enterprise and DE×enterprise. Country sequencing, channel coverage and SAM built on these weights are wrong for a third of the market — and the mismatch is invisible because the summed shares still equal 1.0.",
 "category": "model-structure",
 "targetNodes": [
  "geo.NL",
  "geo.CH"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "All seven geo nodes are derived from a single colocation-scoped table whose country figures don't reconcile with other benchmarks (summed Statista colo exceeds CBRE's total European capacity), and no second vendor uses the same scope",
   "refs": [
    "digest:geo-region-denominator#c0",
    "digest:geo-region-denominator#c1",
    "digest:geo-region-denominator#c3"
   ]
  },
  {
   "step": "propagation",
   "text": "The segment axis includes enterprise on-prem at 0.29, but enterprise capacity is exactly what colo MW excludes: Switzerland is self-operation-heavy (colo 274 MW vs ~850 MW installed base) and Germany's installed load exceeds its colo figure by ~1,000 MW — the geo weights are the wrong measure for the enterprise slice by construction",
   "refs": [
    "ledger:seg.enterprise",
    "ledger:geo.CH",
    "ledger:geo.DE"
   ]
  },
  {
   "step": "model-impact",
   "text": "NL's 0.28 — a colo-hub weight — is applied to enterprise demand it doesn't represent, while CH's 0.08 understates a self-operation-heavy market; ~29% of TAM is misallocated across countries, distorting SAM reach and the country entry order",
   "refs": [
    "ledger:geo.NL",
    "ledger:serviceableFactor"
   ]
  }
 ],
 "whyMissable": "geo.NL is the greenest node in the geography axis — 'triangulated', Statista and the Dutch Data Center Association agree within 3%. But both sources are colocation-scoped, so the triangulation certifies the precision of the wrong denominator. A maturity flag that says 'well-sourced' hides a scope that says 'wrong measure for a third of the cube'.",
 "expectedObviousness": "low",
 "falsifier": "A total-installed-IT-load country apportionment for CE-7 (all segments) that reproduces the colo-based weights within a few points — i.e., NL ≈ 0.28 and CH ≈ 0.08 of total load, showing colo MW is a fair proxy for the full market.",
 "likelihood": {
  "value": 0.68,
  "rationale": "The ledger's own cross-checks already show CH diverging 0.08 vs 0.13 and DE 0.42 vs 0.53 depending on scope; that the divergence is systematic (colo hubs up, enterprise-heavy countries down) follows directly from the documented scope definitions. [evidence revision: Both quantitative anchors of the mechanism are now independently confirmed by strong sources: DE installed load >2,700 MW vs 1,737 MW colo, and CH ~850 MW installed vs 274 MW colo with CBRE explicitly stating colo excludes self-operated capacity. This converts the scope-mismatch premise from inferred to documented, raising likelihood above the prior. Held below high certainty because the ultimate SAM/sequencing-distortion claim depends on modeling assumptions not directly verified, and NL's enterprise share vs colo-hub inflation was not independently quantified here.]",
  "basis": "evidence",
  "revisedFrom": 0.55
 },
 "perturbation": [
  {
   "nodeId": "geo.NL",
   "op": "set",
   "value": 0.23,
   "note": "Blended weight once the enterprise slice is apportioned on installed load instead of Amsterdam colo MW"
  },
  {
   "nodeId": "geo.CH",
   "op": "set",
   "value": 0.12,
   "note": "Self-operated Swiss capacity re-enters the weighting for the enterprise slice"
  }
 ],
 "indicators": [
  {
   "signal": "National installed-IT-load figures published alongside colo figures",
   "where": "BMWK German data-centre landscape updates; CBRE Suisse commercial vs self-operated capacity reports",
   "threshold": "Installed-load country shares diverging >5pp from the model's colo-based shares",
   "updates": "increases"
  },
  {
   "signal": "Statista vs CBRE scope reconciliation for 2025/2026 vintages",
   "where": "CBRE Europe Data Centres quarterly vs Statista colocation-by-country table updates",
   "threshold": "Gap between summed Statista country colo and CBRE European totals persisting or widening",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Build a dual-denominator geo split: colo MW weights for the hyperscale/colo cells, installed-IT-load weights for the enterprise cells, and recompute the cube",
   "type": "information",
   "voiNodeId": "geo.CH",
   "note": "Cheap desk exercise with sources already in the ledger (BMWK, CBRE Suisse, Mordor installed-base)"
  },
  {
   "action": "Sequence country entry per segment rather than per blended geo weight — e.g., CH/DE for enterprise retrofit, NL for colo — instead of one country ranking for all segments",
   "type": "operational",
   "voiNodeId": null,
   "note": "Prevents the blended weights from steering channel investment into phantom cells"
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
   "title": "Status and development of the German data centre landscape – Executive Summary",
   "sourceType": "industry-report",
   "publisher": "BMWK (Federal Ministry for Economic Affairs and Climate Action)",
   "date": "2025-03",
   "excerpt": "With over 2,000 data centres and an installed IT power demand of over 2,700 MW, Germany is already the largest centre for digital infrastructure in Europe.",
   "url": "https://www.bundeswirtschaftsministerium.de/Redaktion/EN/Publikationen/Digitale-Welt/status-and-development-of-the-german-data-centre-landscape-executive-summary.pdf?__blob=publicationFile&v=2",
   "attached": true
  },
  {
   "title": "CBRE Suisse: latest Swiss data centre market figures",
   "sourceType": "industry-report",
   "publisher": "CBRE Switzerland (via europesays.com)",
   "date": "2026-07-05",
   "excerpt": "La capacité actuellement disponible sur le marché suisse des datacenters, hors infrastructures exploitées pour compte propre, s’élève à 340 MW — colocation figures explicitly exclude self-operated capacity.",
   "url": "https://www.europesays.com/ch-fr/205273/",
   "attached": true
  },
  {
   "title": "Switzerland Data Center Market Size & Growth to 2031",
   "sourceType": "analyst-estimate",
   "publisher": "Mordor Intelligence",
   "date": "2023-05-18",
   "excerpt": "Base Year Market Size (2025) | 850.60 megawatt — installed base far exceeds the ~274 MW Statista colocation figure for Switzerland.",
   "url": "https://www.mordorintelligence.com/industry-reports/switzerland-data-center-market",
   "attached": true
  }
 ],
 "stances": [
